import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"心影","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/心影.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/心影.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/心影.md"};function d(l,a,i,_,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"心影",tabindex:"-1"},[n("心影 "),e("a",{class:"header-anchor",href:"#心影","aria-label":'Permalink to "心影"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),s('<h1 id="心影-1" tabindex="-1">心影 <a class="header-anchor" href="#心影-1" aria-label="Permalink to &quot;心影&quot;">​</a></h1><p>C+1000<br> 心影<br> 被征服者的苦难。</p><p>特性：掘尸三尺，暗地一击</p><p>武器伤害12L，重型武器，双手，体积4</p><p>这是一把银灰金属色调的细长重剑，数条从握柄处延伸出的扭曲的银色钢铁环绕着中心处略微弯曲的黑色剑身。整把剑像是一个符文，又像是一个符号。</p><p>掘尸三尺<br> 支付1点意志，进行一次整轮动作攻击，在接下来的一场景或你下一次攻击前（取低）获得C级魔幻本质的反侦测效果。</p><p>暗地一击<br> 在不能被任何敌对目标精确定位的情况下，你可以用标准动作进行一次攻击。这是一个攻击技能。这次攻击会额外造成3的物理易伤，该易伤效果持续一场景，不可叠加。</p><p>可额外选择支付对应的分数购买额外perk：</p><p>幽魂漫步 1000<br> 持有这把武器的时候移动速度增加20米</p><p>爆发刀剑格D+500<br> 这把武器可以像盾牌一样保护你，提供7/7点偏斜防御</p><p>锯齿刀锋 C+1000<br> 这把武器的伤害上升4L，额外提供5破甲，并且成功造成伤害时额外造成2点创伤来源的流血不良点数。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
